const d = $input.first().json.body;
const esc = (v) => String(v ?? '').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#39;');
const euro = (v) => new Intl.NumberFormat('nl-NL', { style: 'currency', currency: 'EUR' }).format(Number(v ?? 0));
const dateFmt = (s) => new Intl.DateTimeFormat('nl-NL', { dateStyle: 'long' }).format(new Date(s));
const monthLabel = (label) => String(label ?? '').toUpperCase();

const from = d.from ?? {};
const companyName  = from.companyName ?? '';
const companyEmail = from.email ?? '';
const companyWeb   = from.websiteUrl ?? '';
const companyAddr  = from.address ?? '';
const companyKvk   = from.kvkNumber ?? '';
const companyVat   = from.vatNumber ?? '';
const companyIban  = from.iban ?? '';
const companyPhone = from.phone ?? '';
const footerText   = d.defaults?.footerText ?? '';
const termsText    = d.defaults?.termsText ?? '';
const filterLabel  = d.paidOnly ? 'Alleen betaalde facturen' : 'Alle facturen';
const monthlyRows  = Array.isArray(d.monthlyBreakdown)
  ? d.monthlyBreakdown.map((month) => `
      <tr>
        <td>${esc(monthLabel(month.label))}</td>
        <td>${esc(String(month.invoice_count ?? 0))}</td>
        <td>${euro(month.total_ex_vat)}</td>
        <td>${euro(month.total_vat)}</td>
        <td>${euro(month.total_inc_vat)}</td>
      </tr>`).join('')
  : '';

const html = `<!DOCTYPE html>
<html lang="nl">
<head>
<meta charset="UTF-8"/>
<link href="https://fonts.googleapis.com/css2?family=Syne:wght@700;800&family=DM+Sans:wght@400;500;700&display=swap" rel="stylesheet"/>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  :root {
    --orange: #f38b53;
    --ink: #1c2031;
    --cream: #f7f3ee;
    --muted: #6b7280;
    --border: rgba(28,32,49,.1);
  }
  body { font-family: 'DM Sans', Arial, sans-serif; font-size: 13px; line-height: 1.65; color: var(--ink); background: #fff; }
  .top-bar { height: 5px; background: var(--orange); }
  .page { padding: 48px 56px 56px; }
  .header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 44px; }
  .brand { font-family: 'Syne', sans-serif; font-size: 22px; font-weight: 800; color: var(--ink); letter-spacing: -.4px; }
  .brand-dot { display: inline-block; width: 7px; height: 7px; background: var(--orange); border-radius: 50%; margin-left: 2px; vertical-align: middle; position: relative; top: -2px; }
  .brand-sub { font-size: 11px; color: var(--muted); margin-top: 4px; }
  .doc-meta { text-align: right; }
  .doc-meta .doc-type { font-family: 'Syne', sans-serif; font-size: 10px; font-weight: 700; letter-spacing: .14em; text-transform: uppercase; color: var(--orange); margin-bottom: 4px; }
  .doc-meta .nr { font-family: 'Syne', sans-serif; font-size: 20px; font-weight: 800; color: var(--ink); letter-spacing: -.4px; line-height: 1; margin-bottom: 10px; }
  .doc-meta table { margin-left: auto; border-collapse: collapse; }
  .doc-meta table td { font-size: 11.5px; padding: 1.5px 0; }
  .doc-meta table td:first-child { padding-right: 14px; color: var(--muted); text-align: right; }
  .doc-meta table td:last-child { font-weight: 500; color: var(--ink); }
  hr { border: none; border-top: 1px solid var(--border); margin: 0 0 32px; }
  .summary-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; margin-bottom: 32px; }
  .summary-card { background: var(--cream); border-radius: 12px; padding: 18px; }
  .summary-card .label { font-size: 10px; font-weight: 700; letter-spacing: .1em; text-transform: uppercase; color: var(--muted); margin-bottom: 6px; }
  .summary-card .value { font-family: 'Syne', sans-serif; font-size: 18px; font-weight: 700; color: var(--ink); }
  .section { margin-bottom: 28px; }
  .section-label { font-size: 10px; font-weight: 700; letter-spacing: .1em; text-transform: uppercase; color: var(--muted); margin-bottom: 8px; }
  .section p { font-size: 13px; color: var(--ink); line-height: 1.75; opacity: .85; }
  .table { width: 100%; border-collapse: collapse; }
  .table th, .table td { padding: 10px 0; border-bottom: 1px solid var(--border); font-size: 12.5px; }
  .table th { text-align: left; color: var(--muted); font-size: 10px; letter-spacing: .08em; text-transform: uppercase; }
  .table td:last-child, .table th:last-child { text-align: right; }
  .table .total-row td { font-family: 'Syne', sans-serif; font-size: 14px; font-weight: 700; border-top: 2px solid var(--ink); border-bottom: none; padding-top: 14px; }
  .meta-block { margin-bottom: 24px; padding: 20px 24px; background: var(--cream); border-radius: 12px; }
  .meta-row { display: flex; justify-content: space-between; font-size: 12px; color: var(--muted); padding: 4px 0; }
  .meta-row span:last-child { font-weight: 500; color: var(--ink); }
  .terms { font-size: 11px; color: var(--muted); line-height: 1.75; opacity: .8; margin-bottom: 28px; }
  .page-footer { margin-top: 48px; padding-top: 16px; border-top: 1px solid var(--border); font-size: 10.5px; color: var(--muted); opacity: .7; line-height: 1.9; display: flex; justify-content: space-between; gap: 24px; }
  .page-footer .right { text-align: right; }
</style>
</head>
<body>
<div class="top-bar"></div>
<div class="page">
  <div class="header">
    <div>
      <div class="brand">${esc(companyName)}<span class="brand-dot"></span></div>
      <div class="brand-sub">${esc(companyWeb)}${companyWeb && companyEmail ? '&nbsp;&nbsp;·&nbsp;&nbsp;' : ''}${esc(companyEmail)}</div>
    </div>
    <div class="doc-meta">
      <div class="doc-type">Jaaropgave</div>
      <div class="nr">${esc(String(d.year ?? ''))}</div>
      <table>
        <tr><td>Rapporttype</td><td>Financieel jaaroverzicht</td></tr>
        <tr><td>Gegenereerd op</td><td>${dateFmt(d.generatedAt)}</td></tr>
        <tr><td>Filter</td><td>${esc(filterLabel)}</td></tr>
      </table>
    </div>
  </div>

  <hr/>

  <div class="summary-grid">
    <div class="summary-card">
      <div class="label">Aantal facturen</div>
      <div class="value">${esc(String(d.invoiceCount ?? 0))}</div>
    </div>
    <div class="summary-card">
      <div class="label">Omzet ex BTW</div>
      <div class="value">${euro(d.totalExVat)}</div>
    </div>
    <div class="summary-card">
      <div class="label">BTW</div>
      <div class="value">${euro(d.totalVat)}</div>
    </div>
    <div class="summary-card">
      <div class="label">Omzet incl BTW</div>
      <div class="value">${euro(d.totalIncVat)}</div>
    </div>
  </div>

  <div class="meta-block">
    <div class="meta-row"><span>Periode</span><span>${esc(d.period?.startDate ?? '')} t/m ${esc(d.period?.endDate ?? '')}</span></div>
    <div class="meta-row"><span>Bedrijf</span><span>${esc(companyName)}</span></div>
    ${companyIban ? `<div class="meta-row"><span>IBAN</span><span>${esc(companyIban)}</span></div>` : ''}
    ${companyKvk ? `<div class="meta-row"><span>KvK</span><span>${esc(companyKvk)}</span></div>` : ''}
    ${companyVat ? `<div class="meta-row"><span>BTW-nummer</span><span>${esc(companyVat)}</span></div>` : ''}
  </div>

  <div class="section">
    <div class="section-label">Maandelijkse uitsplitsing</div>
    <table class="table">
      <thead>
        <tr>
          <th>Maand</th>
          <th>Aantal</th>
          <th>Ex BTW</th>
          <th>BTW</th>
          <th>Incl BTW</th>
        </tr>
      </thead>
      <tbody>
        ${monthlyRows}
        <tr class="total-row">
          <td>Totaal</td>
          <td>${esc(String(d.invoiceCount ?? 0))}</td>
          <td>${euro(d.totalExVat)}</td>
          <td>${euro(d.totalVat)}</td>
          <td>${euro(d.totalIncVat)}</td>
        </tr>
      </tbody>
    </table>
  </div>

  ${termsText ? `<div class="terms">${esc(termsText)}</div>` : ''}

  <div class="page-footer">
    <div>
      ${esc(companyName)}<br/>
      ${companyAddr ? esc(companyAddr) + '<br/>' : ''}
      ${esc(companyEmail)}${companyPhone ? ' &nbsp;·&nbsp; ' + esc(companyPhone) : ''}
    </div>
    <div class="right">
      ${companyKvk ? 'KVK ' + esc(companyKvk) + '<br/>' : ''}
      ${companyVat ? 'BTW ' + esc(companyVat) + '<br/>' : ''}
      Jaaropgave ${esc(String(d.year ?? ''))}
      ${footerText ? '<br/>' + esc(footerText) : ''}
    </div>
  </div>
</div>
</body>
</html>`;

return [{ json: { ...d, html } }];
